(()=>{"use strict";document.addEventListener("DOMContentLoaded",function(){let t=document.getElementsByClassName("tag-cloud");if(!t.length)return;let e=Number.MAX_VALUE,n=5e-324;for(let l of t)for(let t of l.children){let l=parseInt(t.lastElementChild?.textContent)||1;e=Math.min(e,l),n=Math.max(n,l)}if(e>n)return;let l=100/Math.sqrt(n-e+1);for(let n of t)for(let t of n.children){let n=parseInt(t.lastElementChild?.textContent)||1;t.style.fontSize=50+Math.sqrt(n-e+1)*l+"%"}})})();